import pyodbc, json

conn = pyodbc.connect(
    'DRIVER={ODBC Driver 17 for SQL Server};'
    'SERVER=ushou102-exap1;DATABASE=searates;UID=sean;PWD=4peiling;'
)
cursor = conn.cursor()

query = """
SELECT
    dest.Name, dest.Country, dest.Country_Code, dest.LOCode,
    ROUND(TRY_CAST(dest.Lat AS FLOAT), 4) AS Lat,
    ROUND(TRY_CAST(dest.Lng AS FLOAT), 4) AS Lng,
    COUNT(DISTINCT h.TrackNumber) AS Shipments
FROM sealine_header h
JOIN (SELECT TrackNumber, MIN(Id) AS First_Id FROM sealine_locations GROUP BY TrackNumber) orig_seq ON h.TrackNumber = orig_seq.TrackNumber
JOIN sealine_locations orig ON orig.TrackNumber = orig_seq.TrackNumber AND orig.Id = orig_seq.First_Id AND orig.LOCode LIKE 'USHOU%'
JOIN (SELECT TrackNumber, MAX(Id) AS Last_Id FROM sealine_locations GROUP BY TrackNumber) dest_seq ON h.TrackNumber = dest_seq.TrackNumber
JOIN sealine_locations dest ON dest.TrackNumber = dest_seq.TrackNumber AND dest.Id = dest_seq.Last_Id
    AND TRY_CAST(dest.Lat AS FLOAT) IS NOT NULL AND TRY_CAST(dest.Lng AS FLOAT) IS NOT NULL
WHERE h.Status = 'IN_TRANSIT'
GROUP BY dest.Name, dest.Country, dest.Country_Code, dest.LOCode, dest.Lat, dest.Lng
ORDER BY Shipments DESC
"""

cursor.execute(query)
rows = cursor.fetchall()
destinations = [{'name': r[0], 'country': r[1], 'cc': r[2] or '', 'locode': r[3] or '',
