  if (ratio > 0.05) return '#f1c40f';
  return '#3498db';
}}

function getRadius(count) {{
  return Math.max(6, Math.sqrt(count / maxCount) * 40);
}}

destinations.forEach((d, i) => {{
  const color = getColor(d.count);
  const r = getRadius(d.count);
