      <div class="dest-bar" style="width:${{barW}}%"></div>
    </div>
    <span class="dest-count">${{d.count}}</span>`;
  item.onclick = () => {{
    map.setView([d.lat, d.lng], 5);
    markers[i].openPopup();
  }};
  list.appendChild(item);
}});

// Legend
const legend = L.control({{position:'bottomleft'}});
legend.onAdd = () => {{
  const div = L.DomUtil.create('div','legend');
  div.innerHTML = `
    <div class="legend-title">Shipments</div>
    <div class="legend-item"><span style="width:18px;height:18px;border-radius:50%;background:#e74c3c;display:inline-block;opacity:.85"></span> High (&gt;50%)</div>
    <div class="legend-item"><span style="width:14px;height:14px;border-radius:50%;background:#e67e22;display:inline-block;opacity:.85"></span> Medium (20-50%)</div>
    <div class="legend-item"><span style="width:10px;height:10px;border-radius:50%;background:#f1c40f;display:inline-block;opacity:.85"></span> Low (5-20%)</div>
    <div class="legend-item"><span style="width:8px;height:8px;border-radius:50%;background:#3498db;display:inline-block;opacity:.85"></span> Minimal (&lt;5%)</div>
    <div class="legend-item" style="margin-top:6px;border-top:1px solid #0f3460;padding-top:6px;">
      <span style="width:20px;height:20px;border-radius:50%;background:#f39c12;display:inline-block;font-size:11px;display:flex;align-items:center;justify-content:center;">✦</span> Houston Origin
    </div>`;
  return div;
}};
legend.addTo(map);
</script>
</body>
</html>"""

